var grTemplateTask = new GlideRecord('x_153465_discovert_route_tasks');
grTemplateTask.query();
while (grTemplateTask.next()) {
	if(grTemplateTask.work_item_type != grTemplateTask.tasker_type.work_type){
		grTemplateTask.work_item_type = grTemplateTask.tasker_type.work_type;
		grTemplateTask.update();
	}
}
